// Solution: use cheerio to parse the HTML anchor tag and check if it has a 'href' attribute and if the attribute contains a valid URL
function solve(s) {
    const $ = cheerio.load(s);
    const tag = $('a');
    if (tag.length === 0 || !tag.attr('href')) return false;
    const href = tag.attr('href');
    if (!new URL(href).hostname) return false;
    return true;
}

