class Solution:
    def solve(self, s: str) -> bool:
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(s, 'html.parser')
        tag = soup.find('a')
        if not tag or not tag.get('href'):
            return False
        href = tag.get('href')
        try:
            new_url = URL(href)
            return new_url.hostname
        except ValueError:
            return False
